function solve(nums, queries) {
    const unique = [...new Set(nums)].sort((a, b) => a - b);
    const mapping = new Map();
    for (let i = 0; i < unique.length; i++) {
        mapping.set(unique[i], i);
    }
    const orig = unique;
    const arr = nums.map(x => mapping.get(x));

    const n = nums.length;
    const block_size = Math.floor(Math.sqrt(n));

    const sorted_queries = queries.map((q, i) => [q[0], q[1], q[2], i]).sort((a, b) => {
        const blockA = Math.floor(a[0] / block_size);
        const blockB = Math.floor(b[0] / block_size);
        if (blockA !== blockB) {
            return blockA - blockB;
        }
        if (blockA % 2 === 0) {
            return a[1] - b[1];
        } else {
            return b[1] - a[1];
        }
    });

    const ans = new Array(queries.length).fill(0);
    const freq = new Array(unique.length).fill(0);
    let l = 0, r = -1;
    const distinct_values_in_window = new Set();

    function add(x) {
        distinct_values_in_window.add(x);
        const old = freq[x];
        freq[x]++;
    }

    function remove(x) {
        const old = freq[x];
        freq[x]--;
        if (freq[x] === 0) {
            distinct_values_in_window.delete(x);
        }
    }

    for (const [ql, qr, threshold, origIdx] of sorted_queries) {
        while (r < qr) {
            r++;
            add(arr[r]);
        }
        while (r > qr) {
            remove(arr[r]);
            r--;
        }
        while (l < ql) {
            remove(arr[l]);
            l++;
        }
        while (l > ql) {
            l--;
            add(arr[l]);
        }

        let bestCandidate = -1;
        let bestFreq = -1;
        for (const compVal of distinct_values_in_window) {
            const count = freq[compVal];
            if (count < threshold) continue;
            if (count > bestFreq) {
                bestFreq = count;
                bestCandidate = orig[compVal];
            } else if (count === bestFreq) {
                if (orig[compVal] < bestCandidate) {
                    bestCandidate = orig[compVal];
                }
            }
        }
        ans[origIdx] = bestCandidate;
    }

    return ans;
}
