    const n = nums.length;
    const distinctArray = Array.from(new Set(nums));
    const distinctCount = distinctArray.length;
    const mapping = new Map();
    for (let i = 0; i < distinctCount; i++) {
        mapping.set(distinctArray[i], i);
    }
    const discretized = nums.map(num => mapping.get(num));

    const blockSize = Math.ceil(Math.sqrt(n));
    const m = queries.length;
    const q = queries.map((query, idx) => ({
        l: query[0],
        r: query[1],
        threshold: query[2],
        idx: idx
    }));
    q.sort((a, b) => {
        const blockA = Math.floor(a.l / blockSize);
        const blockB = Math.floor(b.l / blockSize);
        if (blockA !== blockB) {
            return blockA - blockB;
        }
        return a.r - b.r;
    });

    const freq = Array(distinctCount).fill(0);
    let lPtr = 0;
    let rPtr = -1;
    const ans = Array(m);

    const add = (id) => {
        freq[id]++;
    };

    const remove = (id) => {
        freq[id]--;
    };

    for (const { l, r, threshold, idx } of q) {
        while (rPtr < r) {
            rPtr++;
            add(discretized[rPtr]);
        }
        while (rPtr > r) {
            remove(discretized[rPtr]);
            rPtr--;
        }
        while (lPtr < l) {
            remove(discretized[lPtr]);
            lPtr++;
        }
        while (lPtr > l) {
            lPtr--;
            add(discretized[lPtr]);
        }

        let candidate = -1;
        let maxFreq = 0;
        for (let id = 0; id < distinctCount; id++) {
            if (freq[id] === 0) continue;
            if (freq[id] >= threshold) {
                if (freq[id] > maxFreq) {
                    maxFreq = freq[id];
                    candidate = distinctArray[id];
                } else if (freq[id] === maxFreq) {
                    if (distinctArray[id] < candidate) {
                        candidate = distinctArray[id];
                    }
                }
            }
        }
        ans[idx] = candidate;
    }

    return ans;
}
